import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Safe code - Buffer overflow prevention
        char[] buffer = new char[10];
        int length = Math.min(userInput.length(), buffer.length); // Limit copied characters to buffer size
        userInput = userInput.substring(0, length); // Ensure only up to 'length' characters are considered
        userInput.getChars(0, length, buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

